27	export function isMediaAssetPubliclyVisible(asset: MediaAssetAccessRecord) {
28	  if (asset.kind === "note-image") {
29	    return Boolean(asset.note?.isPublished && asset.note.markdown.includes(getMediaAssetPath(asset.id)));
30	  }
