39	export function resolveMediaAssetAccess(asset: MediaAssetAccessRecord, viewerOwnerId: string | null): MediaAccessMode | null {
40	  if (viewerOwnerId && viewerOwnerId === asset.ownerId) {
41	    return "owner";
42	  }
43	
44	  if (isMediaAssetPubliclyVisible(asset)) {
45	    return "public";
46	  }
47	
48	  return null;
