16	export async function getReadableMediaAsset(assetId: string, viewerOwnerId: string | null): Promise<ReadableMediaAsset | null> {
17	  const asset = await mediaRepo.findAccessRecordById(assetId);
18	
19	  if (!asset) {
20	    return null;
21	  }
22	
23	  const accessMode = resolveMediaAssetAccess(asset, viewerOwnerId);
24	
25	  if (!accessMode) {
26	    return null;
27	  }
28	
29	  try {
30	    const body = new Uint8Array(await readFile(resolveMediaStoragePath(asset.storageKey)));
31	
32	    return {
33	      accessMode,
34	      body,
35	      contentType: asset.contentType,
36	      sizeBytes: asset.sizeBytes
37	    };
38	  } catch (error) {
39	    if ((error as NodeJS.ErrnoException).code === "ENOENT") {
40	      return null;
41	    }
42	
43	    throw error;
44	  }
45	}

